 * 基準データ: CWRU 6205-2RS JEM SKF（nb=9, bd=7.94mm, pd=38.5mm, phi=0°）
 */

'use strict';

const MechSense = require('../.会社/自動設計/技術部/mechsense-core.js');

let pass = 0, fail = 0;
const PASS = '\x1b[32m✅ PASS\x1b[0m';
const FAIL = '\x1b[31m❌ FAIL\x1b[0m';

function check(label, actual, expected, tol) {
  const ok = Math.abs(actual - expected) <= tol;
  console.log(`${ok ? PASS : FAIL}  ${label}: ${actual.toFixed(4)} (expect ${expected.toFixed(4)}, tol ±${tol})`);
  ok ? pass++ : fail++;
  if (!ok) console.log(`        差異: ${(actual - expected).toFixed(6)}`);
}

function checkEq(label, actual, expected) {
  const ok = actual === expected;
  console.log(`${ok ? PASS : FAIL}  ${label}: ${JSON.stringify(actual)} (expect ${JSON.stringify(expected)})`);
  ok ? pass++ : fail++;
}

function checkNull(label, actual) {
  const ok = actual === null;
  console.log(`${ok ? PASS : FAIL}  ${label} is null: ${actual}`);
  ok ? pass++ : fail++;
}

console.log('=== mechsense-core.js v1.3.0 Bearing モジュール検証 ===\n');
console.log(`バージョン: ${MechSense.version}`);
checkEq('version', MechSense.version, '1.3.0');

// ─────────────────────────────────────────────
// Case 1: CWRU 6205-2RS, rpm=1797（Python 実装と照合）
// Python: BearingFrequencyCalculator(rpm=1797, spec=CWRU_6205)
//   shaft = 29.950 Hz
//   ratio = (7.94/38.5) × cos(0) = 0.206234...
//   BPFO  = 4.5 × 29.950 × (1 - 0.206234) = 106.93... Hz
//   BPFI  = 4.5 × 29.950 × (1 + 0.206234) = 162.71... Hz
//   BSF   = (38.5/15.88) × 29.950 × (1 - 0.042532) = 69.55... Hz
//   FTF   = 0.5 × 29.950 × (1 - 0.206234) = 11.88... Hz
// ─────────────────────────────────────────────
console.log('\n--- Case 1: CWRU 6205-2RS, rpm=1797（JIS番号指定） ---');
const c1 = MechSense.Bearing.calc({ jis: '6205', rpm: 1797 });
console.log('  error:', c1.error);
checkEq('error=null',    c1.error, null);
checkEq('nb=9',          c1.nb,    9);
check ('shaft',          c1.shaft, 29.950,  0.001);

// ratio = 7.94/38.5 = 0.206234
const ratio6205 = (7.94 / 38.5) * Math.cos(0);
const shaft1797 = 1797 / 60;

const exp_bpfo = (9 / 2) * shaft1797 * (1 - ratio6205);
const exp_bpfi = (9 / 2) * shaft1797 * (1 + ratio6205);
const exp_bsf  = (38.5 / (2 * 7.94)) * shaft1797 * (1 - ratio6205 * ratio6205);
const exp_ftf  = 0.5 * shaft1797 * (1 - ratio6205);

check ('BPFO',           c1.bpfo, exp_bpfo,  0.001);
check ('BPFI',           c1.bpfi, exp_bpfi,  0.001);
check ('BSF',            c1.bsf,  exp_bsf,   0.001);
check ('FTF',            c1.ftf,  exp_ftf,   0.001);

// 高調波: BPFO×2 = 第2次
check ('BPFO 2nd harmonic', c1.harmonics.bpfo[1], exp_bpfo * 2, 0.002);
check ('BPFI 3rd harmonic', c1.harmonics.bpfi[2], exp_bpfi * 3, 0.003);

// ─────────────────────────────────────────────
// Case 2: 直接入力（任意軸受サイズ）
// ─────────────────────────────────────────────
console.log('\n--- Case 2: 直接入力（nb=8, bd=10, pd=50, phi=0, rpm=1500） ---');
const c2 = MechSense.Bearing.calc({ nb: 8, bd: 10, pd: 50, phi_deg: 0, rpm: 1500 });
checkEq('error=null', c2.error, null);
const shaft1500 = 1500 / 60;
const ratio2    = 10 / 50;
check ('shaft', c2.shaft, shaft1500,                           0.001);
check ('BPFO',  c2.bpfo,  4 * shaft1500 * (1 - ratio2),       0.001);
check ('BPFI',  c2.bpfi,  4 * shaft1500 * (1 + ratio2),       0.001);
check ('BSF',   c2.bsf,   2.5 * shaft1500 * (1 - ratio2**2),  0.001);
check ('FTF',   c2.ftf,   0.5 * shaft1500 * (1 - ratio2),     0.001);

// ─────────────────────────────────────────────
// Case 3: 接触角あり（アンギュラ玉軸受風 phi=15°）
// ─────────────────────────────────────────────
console.log('\n--- Case 3: 接触角 phi=15°（警告発生確認） ---');
const c3 = MechSense.Bearing.calc({ nb: 7, bd: 8, pd: 40, phi_deg: 15, rpm: 3000 });
checkEq('error=null',         c3.error,     null);
const phi15  = 15 * Math.PI / 180;
const ratio3 = (8 / 40) * Math.cos(phi15);
