checkEq('DB size = 12', jisNums.length, 12);
checkEq('6205 存在',    MechSense.Bearing.BEARINGS['6205'] !== undefined, true);
checkEq('6306 存在',    MechSense.Bearing.BEARINGS['6306'] !== undefined, true);

// ─────────────────────────────────────────────
// Case 6: バリデーション — 未登録 JIS
// ─────────────────────────────────────────────
console.log('\n--- Case 6: バリデーション ---');
const v1 = MechSense.Bearing.calc({ jis: '9999', rpm: 1000 });
const hasErr1 = v1.error && v1.error.includes('9999');
console.log(`${hasErr1 ? PASS : FAIL}  未登録JIS → error: ${v1.error}`);
hasErr1 ? pass++ : fail++;

const v2 = MechSense.Bearing.calc({ nb: 8, bd: 10, pd: 50, rpm: -100 });
const hasErr2 = v2.error && v2.error.includes('rpm');
console.log(`${hasErr2 ? PASS : FAIL}  rpm<=0 → error: ${v2.error}`);
hasErr2 ? pass++ : fail++;

const v3 = MechSense.Bearing.calc({ nb: 8, bd: 50, pd: 40, rpm: 1000 }); // bd > pd
const hasErr3 = v3.error && v3.error.includes('bd < pd');
console.log(`${hasErr3 ? PASS : FAIL}  bd>=pd → error: ${v3.error}`);
hasErr3 ? pass++ : fail++;

const v4 = MechSense.Bearing.calc({ nb: 8, bd: 10, pd: 50, phi_deg: 95, rpm: 1000 });
const hasErr4 = v4.error && v4.error.includes('phi');
console.log(`${hasErr4 ? PASS : FAIL}  phi>=90° → error: ${v4.error}`);
hasErr4 ? pass++ : fail++;

// ─────────────────────────────────────────────
// Case 7: 既存モジュール非破壊確認
// ─────────────────────────────────────────────
console.log('\n--- Case 7: 既存モジュール非破壊 ---');
const spring = MechSense.Spring.calc({ d: 2.0, D: 15, Na: 5, mat: 'SW-B', P: 50 });
checkEq('Spring.calc 非破壊', spring.error, null);
checkEq('Spring.calc τ/σB正常', spring.ratio < 0.5, true);

const bolt = MechSense.Bolt.calc({ d: 'M10', grade: '10.9', partMat: 'steel', mu: 'dry' });
checkEq('Bolt.calc 非破壊',    bolt.error,         null);

const res = MechSense.Resonance.calc({ d: 2.0, D: 15, Na: 5, mat: 'SW-B' });
checkEq('Resonance.calc 非破壊', res.error, null);

// ─────────────────────────────────────────────
// 結果
// ─────────────────────────────────────────────
console.log(`\n${'='.repeat(50)}`);
console.log(`結果: ${pass} PASS / ${fail} FAIL`);
if (fail === 0) {
  console.log('\x1b[32m\n全テスト PASS — Bearing モジュール実装は正確\x1b[0m');
} else {
  console.log('\x1b[31m\n❌ 失敗あり — 上記を確認してください\x1b[0m');
  process.exit(1);
}

